#include<bits/stdc++.h>
using namespace std;
int n,m,a[20][20];
long long ans=0,dp[530000][20];
int main()
{
	cin>>n>>m;
	int t=1<<n;
	for(int i=1;i<=m;i++)
	{
		int x,y;
		cin>>x>>y;
		a[x-1][y-1]=1,a[y-1][x-1]=1;
	}
	for(int i=0;i<n;i++)dp[1<<i][i]=1;
	for(int i=1;i<=t;i++)
	{
		for(int j=0;j<n;j++)
		{
			if(!dp[i][j])continue;
			for(int k=0;k<n;k++)
			{
				if(!a[j][k])continue;
				if((i&-i)>1<<k)continue;
				if(1<<k&i)
				{
					if(1<<k==(i&-i))
					{
						ans+=dp[i][j];
					}
				}
				else dp[i|1<<k][k]+=dp[i][j];
			}
		}
	}
	cout<<(ans-m)/2;
	return 0;
}
